// Germantown Village — July 2026 Social Media Calendar
// Generated by Marée Creative for Bellamare Development

const {
  Document, Packer, Paragraph, TextRun, Table, TableRow, TableCell,
  Header, Footer, AlignmentType, HeadingLevel, BorderStyle, WidthType,
  ShadingType, VerticalAlign, PageNumber, PageBreak, LevelFormat,
  ExternalHyperlink
} = require('docx');
const fs = require('fs');

// ─── COLORS ───────────────────────────────────────────────────────────────────
const NAVY    = "1A3A5C";   // primary dark
const BLUE    = "2E75B6";   // accent
const LBLUE   = "D5E8F0";   // light header fill
const TEAL    = "0D6E6E";   // week accent
const OFFWHT  = "F7F9FC";   // alternating row fill
const CORAL   = "C0392B";   // flag color for client-needed items
const CORAL_L = "FDECEA";   // light coral fill for flagged posts

// ─── BORDERS ──────────────────────────────────────────────────────────────────
const cellBorder = { style: BorderStyle.SINGLE, size: 1, color: "CCCCCC" };
const allBorders = { top: cellBorder, bottom: cellBorder, left: cellBorder, right: cellBorder };
const noBorder = { style: BorderStyle.NONE, size: 0, color: "FFFFFF" };
const noBorders = { top: noBorder, bottom: noBorder, left: noBorder, right: noBorder };

// ─── HELPERS ──────────────────────────────────────────────────────────────────
function h1(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_1,
    children: [new TextRun({ text, font: "Arial", size: 34, bold: true, color: NAVY })],
    spacing: { before: 360, after: 120 },
  });
}

function h2(text, color = NAVY) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_2,
    children: [new TextRun({ text, font: "Arial", size: 28, bold: true, color })],
    spacing: { before: 300, after: 100 },
  });
}

function h3(text, color = BLUE) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_3,
    children: [new TextRun({ text, font: "Arial", size: 24, bold: true, color })],
    spacing: { before: 240, after: 80 },
  });
}

function body(text, opts = {}) {
  return new Paragraph({
    children: [new TextRun({
      text,
      font: "Arial",
      size: opts.size || 22,
      bold: opts.bold || false,
      italic: opts.italic || false,
      color: opts.color || "222222",
    })],
    spacing: { before: opts.spaceBefore || 60, after: opts.spaceAfter || 60 },
    alignment: opts.align || AlignmentType.LEFT,
  });
}

function label(text, value, flagged = false) {
  return new Paragraph({
    children: [
      new TextRun({ text: text + ": ", font: "Arial", size: 22, bold: true, color: flagged ? CORAL : NAVY }),
      new TextRun({ text: value, font: "Arial", size: 22, color: flagged ? CORAL : "333333" }),
    ],
    spacing: { before: 40, after: 40 },
  });
}

function rule() {
  return new Paragraph({
    border: { bottom: { style: BorderStyle.SINGLE, size: 4, color: LBLUE, space: 2 } },
    spacing: { before: 120, after: 120 },
    children: [],
  });
}

function pageBreak() {
  return new Paragraph({ children: [new PageBreak()] });
}

function spacer(lines = 1) {
  return new Paragraph({ children: [new TextRun("")], spacing: { before: lines * 100, after: 0 } });
}

function flagNote(text) {
  return new Paragraph({
    children: [
      new TextRun({ text: "⚑ CLIENT INPUT NEEDED: ", font: "Arial", size: 20, bold: true, color: CORAL }),
      new TextRun({ text, font: "Arial", size: 20, color: CORAL }),
    ],
    spacing: { before: 60, after: 60 },
    indent: { left: 360 },
  });
}

// ─── POST BLOCK ───────────────────────────────────────────────────────────────
// Creates a self-contained post block with a colored header row and content cells
function postBlock(dayDate, platform, pillar, format, caption, visual, cta, hashtags, flagged = false) {
  const headerFill = flagged ? CORAL_L : LBLUE;
  const headerText = flagged ? CORAL : NAVY;
  const W = 9360;
  const C1 = 1800, C2 = 1800, C3 = 1800, C4 = 3960;

  function hdrCell(text, w) {
    return new TableCell({
      borders: allBorders,
      width: { size: w, type: WidthType.DXA },
      shading: { fill: headerFill, type: ShadingType.CLEAR },
      margins: { top: 80, bottom: 80, left: 120, right: 120 },
      children: [new Paragraph({
        children: [new TextRun({ text, font: "Arial", size: 18, bold: true, color: headerText })],
      })],
    });
  }

  function contentCell(lines, w, fill = "FFFFFF") {
    const paragraphs = lines.map(line => {
      if (typeof line === "string") {
        return new Paragraph({
          children: [new TextRun({ text: line, font: "Arial", size: 20, color: "222222" })],
          spacing: { before: 40, after: 40 },
        });
      }
      return line;
    });
    return new TableCell({
      borders: allBorders,
      width: { size: w, type: WidthType.DXA },
      shading: { fill, type: ShadingType.CLEAR },
      margins: { top: 80, bottom: 80, left: 120, right: 120 },
      columnSpan: undefined,
      children: paragraphs,
    });
  }

  // Full-width cell spanning all columns
  function fullCell(lines, fill = "FFFFFF") {
    const paragraphs = lines.map(line => {
      if (typeof line === "string") {
        return new Paragraph({
          children: [new TextRun({ text: line, font: "Arial", size: 20, color: "222222" })],
          spacing: { before: 40, after: 40 },
        });
      }
      return line;
    });
    return new TableCell({
      borders: allBorders,
      width: { size: W, type: WidthType.DXA },
      shading: { fill, type: ShadingType.CLEAR },
      margins: { top: 80, bottom: 80, left: 120, right: 120 },
      columnSpan: 4,
      children: paragraphs,
    });
  }

  function captionParagraphs(text) {
    return text.split("\n").map(line =>
      new Paragraph({
        children: [new TextRun({ text: line, font: "Arial", size: 20, color: "222222" })],
        spacing: { before: 30, after: 30 },
      })
    );
  }

  const rows = [
    // Header row
    new TableRow({
      children: [
        hdrCell(dayDate, C1),
        hdrCell(platform, C2),
        hdrCell(pillar, C3),
        hdrCell(format, C4),
      ],
    }),
    // Caption row
    new TableRow({
      children: [
        new TableCell({
          borders: allBorders,
          width: { size: 1440, type: WidthType.DXA },
          shading: { fill: OFFWHT, type: ShadingType.CLEAR },
          margins: { top: 80, bottom: 80, left: 120, right: 120 },
          verticalAlign: VerticalAlign.TOP,
          children: [new Paragraph({
            children: [new TextRun({ text: "CAPTION", font: "Arial", size: 18, bold: true, color: BLUE })],
          })],
        }),
        new TableCell({
          borders: allBorders,
          width: { size: 7920, type: WidthType.DXA },
          shading: { fill: "FFFFFF", type: ShadingType.CLEAR },
          margins: { top: 80, bottom: 80, left: 120, right: 120 },
          columnSpan: 3,
          children: captionParagraphs(caption),
        }),
      ],
    }),
    // Visual row
    new TableRow({
      children: [
        new TableCell({
          borders: allBorders,
          width: { size: 1440, type: WidthType.DXA },
          shading: { fill: OFFWHT, type: ShadingType.CLEAR },
          margins: { top: 80, bottom: 80, left: 120, right: 120 },
          verticalAlign: VerticalAlign.TOP,
          children: [new Paragraph({
            children: [new TextRun({ text: "VISUAL", font: "Arial", size: 18, bold: true, color: BLUE })],
          })],
        }),
        new TableCell({
          borders: allBorders,
          width: { size: 4680, type: WidthType.DXA },
          shading: { fill: "FFFFFF", type: ShadingType.CLEAR },
          margins: { top: 80, bottom: 80, left: 120, right: 120 },
          columnSpan: 2,
          children: [new Paragraph({
            children: [new TextRun({ text: visual, font: "Arial", size: 20, italic: true, color: "555555" })],
          })],
        }),
        new TableCell({
          borders: allBorders,
          width: { size: 3240, type: WidthType.DXA },
          shading: { fill: OFFWHT, type: ShadingType.CLEAR },
          margins: { top: 80, bottom: 80, left: 120, right: 120 },
          children: [
            new Paragraph({
              children: [new TextRun({ text: "CTA", font: "Arial", size: 18, bold: true, color: BLUE })],
              spacing: { after: 40 },
            }),
            new Paragraph({
              children: [new TextRun({ text: cta, font: "Arial", size: 20, color: "222222" })],
              spacing: { after: 40 },
            }),
            ...(hashtags ? [
              new Paragraph({
                children: [new TextRun({ text: "HASHTAGS", font: "Arial", size: 18, bold: true, color: BLUE })],
                spacing: { before: 60, after: 40 },
              }),
              new Paragraph({
                children: [new TextRun({ text: hashtags, font: "Arial", size: 18, color: "666666", italic: true })],
              }),
            ] : []),
          ],
        }),
      ],
    }),
  ];

  return new Table({
    width: { size: W, type: WidthType.DXA },
    columnWidths: [1440, 2520, 1800, 3600],
    rows,
  });
}

// ─── WEEK BANNER ─────────────────────────────────────────────────────────────
function weekBanner(weekNum, dateRange, theme, tenant) {
  const W = 9360;
  return new Table({
    width: { size: W, type: WidthType.DXA },
    columnWidths: [9360],
    rows: [
      new TableRow({
        children: [
          new TableCell({
            borders: noBorders,
            width: { size: W, type: WidthType.DXA },
            shading: { fill: NAVY, type: ShadingType.CLEAR },
            margins: { top: 120, bottom: 120, left: 200, right: 200 },
            children: [
              new Paragraph({
                children: [
                  new TextRun({ text: `WEEK ${weekNum}  `, font: "Arial", size: 28, bold: true, color: "FFFFFF" }),
                  new TextRun({ text: dateRange, font: "Arial", size: 24, color: "AACCEE" }),
                ],
              }),
              new Paragraph({
                children: [new TextRun({ text: theme, font: "Arial", size: 21, italic: true, color: "DDEEEE" })],
                spacing: { before: 60 },
              }),
              new Paragraph({
                children: [new TextRun({ text: `Featured: ${tenant}`, font: "Arial", size: 20, bold: true, color: "FFD700" })],
                spacing: { before: 40 },
              }),
            ],
          }),
        ],
      }),
    ],
  });
}

