// ─── STORIES PLAN TABLE ───────────────────────────────────────────────────────
function storiesTable() {
  const W = 9360;
  const cols = [1200, 2000, 3160, 3000];

  function hdr(text, w) {
    return new TableCell({
      borders: allBorders, width: { size: w, type: WidthType.DXA },
      shading: { fill: TEAL, type: ShadingType.CLEAR },
      margins: { top: 80, bottom: 80, left: 120, right: 120 },
      children: [new Paragraph({ children: [new TextRun({ text, font: "Arial", size: 18, bold: true, color: "FFFFFF" })] })],
    });
  }

  function cell(text, w, fill = "FFFFFF") {
    return new TableCell({
      borders: allBorders, width: { size: w, type: WidthType.DXA },
      shading: { fill, type: ShadingType.CLEAR },
      margins: { top: 60, bottom: 60, left: 120, right: 120 },
      children: text.split("\n").map(line =>
        new Paragraph({ children: [new TextRun({ text: line, font: "Arial", size: 19, color: "222222" })], spacing: { before: 30, after: 30 } })
      ),
    });
  }

  const plan = [
    ["Monday", "Week Preview", "3 frames: title card, tenant spotlight teaser, CTA to link in bio", "Start of week rhythm — set expectations, create anticipation"],
    ["Tue–Wed", "Tenant Behind-the-Scenes", "3–5 frames: product/service detail, space walkthrough, team moment", "Deepen featured tenant story — content that doesn't fit a feed post"],
    ["Thursday", "Engagement Poll / Q&A", "1–2 frames: 'Have you been to [tenant]?' poll or 'What's your go-to at GV?' question", "Gather community signal — high-engagement Story format"],
    ["Friday", "Weekend Preview + Hours", "3 frames: what's happening this weekend, hours reminder, parking note", "Reduce friction — give people the info they need to show up Saturday"],
    ["Saturday", "Live Weekend Coverage", "5–10 frames: real-time content from the square, vendors, people, food, fun", "Authenticity and urgency — people love being part of what's happening now"],
    ["Sunday", "Week Recap + Teaser", "2–3 frames: best moment from the week, preview of next week's spotlight", "Close the loop; keep followers coming back Monday"],
  ];

  return new Table({
    width: { size: W, type: WidthType.DXA },
    columnWidths: cols,
    rows: [
      new TableRow({
        tableHeader: true,
        children: [hdr("Day", cols[0]), hdr("Story Type", cols[1]), hdr("Frame Content", cols[2]), hdr("Why It Works", cols[3])],
      }),
      ...plan.map(([day, type, content, why], i) =>
        new TableRow({
          children: [
            cell(day, cols[0], i % 2 === 0 ? "FFFFFF" : OFFWHT),
            cell(type, cols[1], i % 2 === 0 ? "FFFFFF" : OFFWHT),
            cell(content, cols[2], i % 2 === 0 ? "FFFFFF" : OFFWHT),
            cell(why, cols[3], i % 2 === 0 ? "FFFFFF" : OFFWHT),
          ],
        })
      ),
    ],
  });
}

